// Generated by OrchestKit Claude Plugin

/**
 * Unit tests for playground-presence-warner: the opt-in-by-detection change.
 *
 * The warner must stay silent unless the repo actually defines the
 * `playground-check` CI gate — otherwise its "CI will reject your PR" message
 * is a factually false claim in the many repos without that job (#2574).
 */

import { describe, it, expect, afterEach } from 'vitest';
import { mkdtempSync, mkdirSync, writeFileSync, rmSync } from 'node:fs';
import { tmpdir } from 'node:os';
import { join } from 'node:path';
import { repoDefinesPlaygroundGate } from '../../pretool/bash/playground-presence-warner.js';

const dirs: string[] = [];
function scratch(): string {
  const d = mkdtempSync(join(tmpdir(), 'ork-warner-'));
  dirs.push(d);
  return d;
}
function writeWorkflow(root: string, name: string, body: string): void {
  const wf = join(root, '.github', 'workflows');
  mkdirSync(wf, { recursive: true });
  writeFileSync(join(wf, name), body);
}

afterEach(() => {
  for (const d of dirs.splice(0)) rmSync(d, { recursive: true, force: true });
});

describe('repoDefinesPlaygroundGate (#2574)', () => {
  it('is false when there is no .github/workflows dir', () => {
    expect(repoDefinesPlaygroundGate(scratch())).toBe(false);
  });

  it('is false when workflows exist but none define the gate', () => {
    const root = scratch();
    writeWorkflow(root, 'ci.yml', 'name: CI\njobs:\n  build:\n    runs-on: ubuntu-latest\n');
    expect(repoDefinesPlaygroundGate(root)).toBe(false);
  });

  it('is true when a workflow defines the playground-check job', () => {
    const root = scratch();
    writeWorkflow(root, 'ci.yml', 'jobs:\n  playground-check:\n    name: PR Playground\n');
    expect(repoDefinesPlaygroundGate(root)).toBe(true);
  });

  it('detects the gate in a .yaml (not just .yml) workflow', () => {
    const root = scratch();
    writeWorkflow(root, 'checks.yaml', 'jobs:\n  playground-check: {}\n');
    expect(repoDefinesPlaygroundGate(root)).toBe(true);
  });

  it('ignores non-workflow files in the dir', () => {
    const root = scratch();
    writeWorkflow(root, 'notes.txt', 'playground-check mentioned here but not a workflow');
    expect(repoDefinesPlaygroundGate(root)).toBe(false);
  });
});
